// Fold (icmp eq X, C) | (icmp ugt (add X, -C), Y) -> icmp uge (add X, -C-1), Y
static Value *foldNoWrapAddICmps(ICmpInst *Cmp0, ICmpInst *Cmp1,
                                 bool IsAnd, InstCombiner::BuilderTy &Builder) {
  // Match: icmp ne/eq X, C
  ICmpInst::Predicate Pred0;
  Value *X;
  const APInt *C;
  if (!match(Cmp0, m_ICmp(Pred0, m_Value(X), m_APIntAllowUndef(C))))
    return nullptr;

  bool IsNE = (Pred0 == ICmpInst::ICMP_NE);
  bool IsEQ = (Pred0 == ICmpInst::ICMP_EQ);
  if ((IsAnd && !IsNE) || (!IsAnd && !IsEQ))
    return nullptr;

  // Match: icmp ule/ugt (add X, -C), Y
  ICmpInst::Predicate Pred1;
  Value *Op0, *Op1;
  if (!match(Cmp1, m_ICmp(Pred1, m_Value(Op0), m_Value(Op1))))
    return nullptr;

  const APInt *AddC;
  Value *Y;
  if (match(Op0, m_Add(m_Specific(X), m_APIntAllowUndef(AddC)))) {
    Y = Op1;
  } else if (match(Op1, m_Add(m_Specific(X), m_APIntAllowUndef(AddC)))) {
    Y = Op0;
    Pred1 = ICmpInst::getSwappedPredicate(Pred1);
  } else {
    return nullptr;
  }

  // Check that the add constant is the negation of the icmp constant.
  // For vectors, we allow undef elements to match any value.
  if (*AddC != -*C)
    return nullptr;

