    // (X + (-C)) <= Y  &&  X != C  ->  (X + (-C) - 1) < Y
    APInt NewAddC = *AddC - 1;
    if (NewAddC.isZero())
      return Builder.CreateICmpULT(X, Y);
    return Builder.CreateICmpULT(Builder.CreateAdd(X, ConstantInt::get(X->getType(), NewAddC)), Y);
  }
  if (!IsAnd && Pred1 == ICmpInst::ICMP_UGT) {
    // (X + (-C)) > Y  ||  X == C  ->  (X + (-C) - 1) >= Y
    APInt NewAddC = *AddC - 1;
    if (NewAddC.isZero())
      return Builder.CreateICmpUGE(X, Y);
    return Builder.CreateICmpUGE(Builder.CreateAdd(X, ConstantInt::get(X->getType(), NewAddC)), Y);
  }

  return nullptr;
}
